// Filter for invoices that need reminders
const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const needsReminder = [];

for (const item of items) {
  const inv = item.json;

  // Skip paid or cancelled invoices
  if (!inv.Invoice_ID || inv.Status === 'Paid' || inv.Status === 'Cancelled') {
    continue;
  }

  const dueDate = new Date(inv.Due_Date);
  dueDate.setHours(0, 0, 0, 0);

  if (isNaN(dueDate.getTime())) continue; // skip invalid dates

  const daysPastDue = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
  const reminderCount = parseInt(inv.Reminder_Count || '0');

  let shouldRemind = false;
  let reminderType = '';

  // Reminder schedule:
  // Day -3: Pre-due reminder (gentle heads-up)
  // Day 0: Due today reminder
  // Day 3: First overdue reminder
  // Day 7: Second overdue (firmer tone)
  // Day 14: Third overdue (urgent)
  // Day 30: Final notice

  const lastReminder = inv.Last_Reminder_Date ? new Date(inv.Last_Reminder_Date) : null;
  const daysSinceLastReminder = lastReminder 
    ? Math.floor((today - lastReminder) / (1000 * 60 * 60 * 24))
    : 999;

  if (daysPastDue === -3 && reminderCount === 0) {
    shouldRemind = true;
    reminderType = 'pre_due';
  } else if (daysPastDue === 0 && reminderCount <= 1) {
    shouldRemind = true;
    reminderType = 'due_today';
  } else if (daysPastDue === 3 && reminderCount <= 2) {
    shouldRemind = true;
    reminderType = 'overdue_gentle';
  } else if (daysPastDue === 7 && reminderCount <= 3) {
    shouldRemind = true;
    reminderType = 'overdue_firm';
  } else if (daysPastDue === 14 && reminderCount <= 4) {
    shouldRemind = true;
    reminderType = 'overdue_urgent';
  } else if (daysPastDue >= 30 && reminderCount <= 5 && daysSinceLastReminder >= 14) {
    shouldRemind = true;
    reminderType = 'final_notice';
  }

  if (shouldRemind) {
    needsReminder.push({
      json: {
        ...inv,
        daysPastDue,
        reminderType,
        reminderCount,
        formattedAmount: `${inv.Amount} ${inv.Currency || 'EUR'}`,
        formattedDueDate: dueDate.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })
      }
    });
  }
}

if (needsReminder.length === 0) {
  // Return a dummy item so the workflow doesn't error
  return [{ json: { noRemindersNeeded: true } }];
}

return needsReminder;

// Build the email content based on reminder type
const inv = $input.first().json;

const templates = {
  pre_due: {
    subject: `Reminder: Invoice ${inv.Invoice_ID} due in 3 days`,
    body: `Hi ${inv.Client_Name},

Just a friendly heads-up that invoice ${inv.Invoice_ID} for ${inv.formattedAmount} is due on ${inv.formattedDueDate}.

If you have any questions about this invoice, please don't hesitate to reach out.

Thank you for your continued business!

Best regards,
[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  },
  due_today: {
    subject: `Invoice ${inv.Invoice_ID} is due today`,
    body: `Hi ${inv.Client_Name},

This is a reminder that invoice ${inv.Invoice_ID} for ${inv.formattedAmount} is due today (${inv.formattedDueDate}).

Please process payment at your earliest convenience. If payment has already been made, please disregard this notice.

Payment details:
- Invoice: ${inv.Invoice_ID}
- Amount: ${inv.formattedAmount}
- Due Date: ${inv.formattedDueDate}

Thank you,
[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  },
  overdue_gentle: {
    subject: `Invoice ${inv.Invoice_ID} — 3 days overdue`,
    body: `Hi ${inv.Client_Name},

I hope you're doing well. I wanted to follow up on invoice ${inv.Invoice_ID} for ${inv.formattedAmount}, which was due on ${inv.formattedDueDate}.

We haven't received payment yet. If there are any issues or if you need to discuss payment arrangements, please let us know.

Best regards,
[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  },
  overdue_firm: {
    subject: `OVERDUE: Invoice ${inv.Invoice_ID} — Action required`,
    body: `Hi ${inv.Client_Name},

This is our second notice regarding invoice ${inv.Invoice_ID} for ${inv.formattedAmount}, now 7 days overdue (due ${inv.formattedDueDate}).

We kindly request that you process this payment as soon as possible. If you've already sent payment, please confirm so we can update our records.

If you have any concerns, please contact us immediately.

Regards,
[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  },
  overdue_urgent: {
    subject: `URGENT: Invoice ${inv.Invoice_ID} — 14 days overdue`,
    body: `Hi ${inv.Client_Name},

Despite previous reminders, invoice ${inv.Invoice_ID} for ${inv.formattedAmount} remains unpaid after 14 days.

We require immediate payment to avoid further action. Please reply to this email or contact us at [REPLACE_WITH_PHONE] to arrange payment.

Invoice: ${inv.Invoice_ID}
Amount Due: ${inv.formattedAmount}
Original Due Date: ${inv.formattedDueDate}

If payment was recently made, please disregard this notice and send us your payment confirmation.

Sincerely,
[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  },
  final_notice: {
    subject: `FINAL NOTICE: Invoice ${inv.Invoice_ID}`,
    body: `Hi ${inv.Client_Name},

This is your final notice regarding invoice ${inv.Invoice_ID} for ${inv.formattedAmount}, which is now ${inv.daysPastDue} days overdue.

If we do not receive payment or a response within 7 days, we may be required to escalate this matter.

Please contact us immediately at [REPLACE_WITH_EMAIL] or [REPLACE_WITH_PHONE].

[REPLACE_WITH_YOUR_NAME]
[REPLACE_WITH_COMPANY_NAME]`
  }
};

const template = templates[inv.reminderType] || templates.overdue_gentle;

return [{
  json: {
    ...inv,
    emailSubject: template.subject,
    emailBody: template.body
  }
}];
